// Normalise Email and Check for Misdirection
const item = $input.first().json;

// Allowed Nexus domains
const nexusDomains = ['nexusintegrations.com', 'nexus-integrations.com'];

// Function to clean email strings
// Removes Markdown links [email](mailto:email) and trims spaces
const cleanEmail = str => {
  if (!str) return '';
  // Remove [text](mailto:email) style formatting
  return str.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1').trim();
};

// Normalize fields
const from = cleanEmail(item.from);
const to = cleanEmail(item.to);
const subject = (item.subject || '').trim();
const body = (item.body || '').trim();

// Validate required fields
if (!from || !body) {
  throw new Error('Missing required fields: from and body are required.');
}

// Initialize misdirected flag
let isMisdirected = false;

// Check all recipients
if (to) {
  // Split by comma for multiple recipients, trim spaces, lowercase
  const recipients = to.split(',').map(email => email.trim().toLowerCase());

  // Check if any recipient is outside allowed domains
  for (let recipient of recipients) {
    const domain = recipient.split('@')[1] || '';
    if (domain && !nexusDomains.includes(domain)) {
      isMisdirected = true;
      break; // One misdirected recipient is enough
    }
  }
}

// Return normalized email object
return [{ json: { from, to, subject, body, isMisdirected } }];

// Misdirected Reply
const item = $input.first().json;

return [{
  json: {
    from: item.from,
    to: item.to,
    subject: item.subject,
    body: item.body,
    category: 'misdirected',
    draft_reply: `Hi,\n\nThank you for reaching out. It appears your email may have been sent to the wrong address. Nexus Integrations handles integration and automation solutions — if you intended to contact us, please email support@nexusintegrations.com directly.\n\nIf this was meant for another company, we apologise for any confusion.\n\nBest regards,\nNexus Integrations Support Team`,
    requires_human: false,
    action: 'reply'
  }
}];

// Parse Classification Node - Robust for GPT Chat API output
const item = $input.first().json;

// Extract the inner content string
let rawText = '{}';
if (item?.message?.content) {
  rawText = item.message.content;
} else if (item?.choices?.[0]?.message?.content) {
  rawText = item.choices[0].message.content;
}

// Remove any Markdown/code block backticks or extra whitespace
rawText = rawText.replace(/```json|```/g, '').trim();

let classification;
try {
  classification = JSON.parse(rawText);
} catch (e) {
  classification = {
    category: 'escalate_support',
    confidence: 0,
    reasoning: 'Parse error',
    urgency: 'high'
  };
}

// Ensure category is valid
const validCategories = ['pricing','setup','security','hr','escalate_sales','escalate_support','escalate_legal','escalate_finance','spam','misdirected'];
if (!validCategories.includes(classification.category)) {
  classification.category = 'escalate_support';
}

// Apply low confidence fallback
if (!classification.confidence || classification.confidence < 0.7) {
  classification.category = 'escalate_support';
}

// Pull original email from "Normalise Email" node
const emailData = $('Normalise Email').first().json;

// Return clean, flattened object
return [{
  json: {
    from: emailData.from,
    to: emailData.to,
    subject: emailData.subject,
    body: emailData.body,
    category: classification.category,
    confidence: classification.confidence,
    reasoning: classification.reasoning,
    urgency: classification.urgency
  }
}];

// Draft Escalation Reply - Polished Version
const item = $input.first().json;

// Define escalation templates with more professional, human-like responses
const escalationMap = {
  escalate_sales: {
    team: 'Sales',
    action: 'escalate_sales',
    message: `Hi ${item.from.split('@')[0].replace(/[.\-_]/g, ' ')},\n\nThank you for reaching out and for your interest in Nexus Integrations! We understand that your team is evaluating our platform and exploring options for your deployment.\n\nI’ve escalated your message to our Sales team, who will review your requirements in detail and get back to you promptly with a tailored solution that fits your needs.\n\nBest regards,\nNexus Integrations Support Team`
  },
  escalate_support: {
    team: 'Engineering',
    action: 'escalate_support',
    message: `Hi ${item.from.split('@')[0].replace(/[.\-_]/g, ' ')},\n\nThank you for contacting Nexus Integrations. We recognize that this is an important issue and want to ensure it’s handled quickly and efficiently.\n\nI’ve escalated your case to our Engineering team. A specialist will reach out to you shortly to resolve your concern.\n\nWe appreciate your patience.\n\nBest regards,\nNexus Integrations Support Team`
  },
  escalate_legal: {
    team: 'Legal',
    action: 'escalate_legal',
    message: `Hi ${item.from.split('@')[0].replace(/[.\-_]/g, ' ')},\n\nThank you for your message. We take requests involving legal agreements or compliance matters very seriously.\n\nYour correspondence has been forwarded to our Legal team, who will review your request thoroughly and respond as soon as possible.\n\nBest regards,\nNexus Integrations Support Team`
  },
  escalate_finance: {
    team: 'Finance',
    action: 'escalate_finance',
    message: `Hi ${item.from.split('@')[0].replace(/[.\-_]/g, ' ')},\n\nThank you for reaching out regarding your billing or invoice issue.\n\nI’ve escalated your email to our Finance team, who will review your account and get back to you promptly with the necessary information.\n\nWe appreciate your patience.\n\nBest regards,\nNexus Integrations Support Team`
  }
};

// Default to support escalation if category not in map
const escalation = escalationMap[item.category] || escalationMap['escalate_support'];

return [{
  json: {
    from: item.from,
    to: item.to,
    subject: item.subject,
    body: item.body,
    category: item.category,
    draft_reply: escalation.message,
    requires_human: true,
    action: escalation.action,
    assigned_team: escalation.team
  }
}];

// Spam / Junk Filter
const item = $input.first().json;

if (item.category === 'spam') {
  return [{
    json: {
      from: item.from,
      to: item.to,
      subject: item.subject,
      body: item.body,
      category: 'spam',
      draft_reply: '',
      requires_human: false,
      action: 'discard'
    }
  }];
}

// All other categories pass through to RAG pipeline
return [{ json: item }];

const data = $input.first().json;

return [{
  json: {
    category: data.category || 'escalate_support',
    draft_reply: data.draft_reply || 'Thank you for contacting Nexus Integrations. We have received your message and a member of our team will be in touch shortly.\n\nBest regards,\nNexus Integrations Support Team'
  }
}];

