const raw = $input.first().json.output || '';

// Clean and parse the JSON string the agent returns
let parsed;
try {
  const cleaned = raw
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  // If parsing fails, wrap the raw text as draft_reply
  parsed = {
    category: 'support',
    draft_reply: raw
  };
}

return [{
  json: {
    category: parsed.category || 'support',
    draft_reply: parsed.draft_reply || raw
  }
}];
